# pyre-ignore-all-errors
"""
Gap 6 — Disclaimer Engine
Wraps all AI-generated outputs with mandatory human_review_required flag,
ai_confidence score, and legal disclaimer text.
"""
from __future__ import annotations

import re
from typing import Any

# ── Legal disclaimer text ─────────────────────────────────────────────────────
_DISCLAIMER_TEXT = (
    "This output was generated by the Arkashri Deterministic Decision Engine. "
    "It constitutes decision support only and does not represent a professional "
    "audit opinion. All AI-generated outputs must be reviewed and confirmed by a "
    "registered Chartered Accountant (ICAI) or equivalent qualified professional "
    "before use in any statutory, regulatory, or compliance context. "
    "Arkashri Technologies Pvt. Ltd. accepts no liability for reliance on "
    "unreviewed AI output."
)

# ICAI Membership Number formats:
#   - Fellow (FCA):   F-123456  or  FCA-123456
#   - Associate (ACA): A-123456 or  ACA-123456
_ICAI_RE = re.compile(
    r"^(?:F|A|FCA|ACA)-?\d{6}$",
    re.IGNORECASE,
)


def validate_icai_reg_no(reg_no: str) -> bool:
    """Returns True if reg_no matches ICAI membership number format."""
    return bool(_ICAI_RE.match(reg_no.strip())) if reg_no else False


def attach_disclaimer(
    output_type: str,
    payload: dict[str, Any],
    ai_confidence: float | None = None,
) -> dict[str, Any]:
    """
    Wrap any AI-generated output with mandatory fields:
      - human_review_required: always True
      - ai_generated: always True
      - ai_confidence: 0.0–1.0 if available
      - output_type: label for the kind of output
      - disclaimer: full legal disclaimer text
    """
    return {
        **payload,
        "human_review_required": True,
        "ai_generated": True,
        "ai_confidence": round(ai_confidence, 4) if ai_confidence is not None else None,
        "output_type": output_type,
        "disclaimer": _DISCLAIMER_TEXT,
    }


def generate_liability_notice(engagement_id: str, signed_by: str | None, icai_reg_no: str | None) -> dict[str, Any]:
    """
    Generate the liability notice block embedded in every sealed report.
    """
    ca_confirmed = bool(signed_by and icai_reg_no and validate_icai_reg_no(icai_reg_no))
    return {
        "liability_notice": {
            "tool": "Arkashri Decision Engine",
            "tool_role": "Decision support — not audit opinion",
            "human_review_required": True,
            "ca_confirmed": ca_confirmed,
            "ca_name": signed_by if ca_confirmed else None,
            "ca_icai_reg_no": icai_reg_no if ca_confirmed else None,
            "disclaimer": _DISCLAIMER_TEXT,
        }
    }
